+      </div>
+      <div
+        style={{
+          fontFamily: "var(--font-mono)",
+          fontSize: isText ? 16 : 28,
+          fontWeight: 600,
+          color: color || "var(--text-primary)",
+          letterSpacing: "-0.02em",
+          lineHeight: 1.1,
+        }}
+      >
+        {displayValue}
+      </div>
+    </div>
+  );
+}
+
+function PortTag({ label, port }: { label: string; port: number }) {
