+      <td style={{ padding: "10px var(--space-4)", whiteSpace: "nowrap" }}>
+        <div style={{ display: "flex", gap: "var(--space-2)" }}>
+          {mod.state === "stopped" && (
+            <ActionButton label="Start" onClick={() => onAction(mod.module_id, "start")} />
