+  );
+}
+
+function Banner({
+  type,
+  message,
+  onDismiss,
+}: {
+  type: "error" | "success";
+  message: string;
+  onDismiss: () => void;
+}) {
+  const isError = type === "error";
+  const color = isError ? "var(--status-error)" : "var(--status-online)";
+  const bgAlpha = isError ? "rgba(248, 81, 73, 0.1)" : "rgba(63, 185, 80, 0.1)";
+  const borderAlpha = isError ? "rgba(248, 81, 73, 0.3)" : "rgba(63, 185, 80, 0.3)";
+
+  return (
+    <div
+      style={{
+        background: bgAlpha,
+        border: `1px solid ${borderAlpha}`,
+        borderRadius: 6,
+        padding: "var(--space-3) var(--space-4)",
+        marginBottom: "var(--space-4)",
+        fontSize: 13,
+        color,
+        display: "flex",
+        justifyContent: "space-between",
+        alignItems: "center",
+      }}
+    >
+      <span>{message}</span>
+      <button
+        onClick={onDismiss}
