+      isCoordinator: isCoord,
+      x: cx + Math.cos(angle) * spread + (Math.random() - 0.5) * 20,
+      y: cy + Math.sin(angle) * spread + (Math.random() - 0.5) * 20,
+      vx: 0,
+      vy: 0,
+      radius: isCoord ? 30 : 20,
